bool vis[N];
int timer, dfn[N], par[N], dep[N];
void solve(int CASE)
{
	int n, m, k; cin >> n >> m >> k;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	if (m == n - 1) {
		// 无环，是个树，二分图染色法
		var col = vector<int>(n + 1);
		int cnt = 0;
		var dfs = [&](var dfs, int now, int fa)->void {
			col[now] = col[fa] ^ 1;
			cnt += col[now];
			for (int to : g[now]) {
				if (to == fa)continue;
				dfs(dfs, to, now);
			}
			};
		dfs(dfs, 1, 0);

		cout << 1 << endl;
		k = (k + 1) / 2;
		if (cnt >= n - cnt) {
			fa(i, 1, n)if (col[i]) {
				cout << i << ' ';
				k--;
				if (k == 0)break;
			}
		}
		else {
			fa(i, 1, n)if (!col[i]) {
				cout << i << ' ';
				k--;
				if (k == 0)break;
			}
		}
	}
	else {
		int min_siz = n + 1;
		var min_cycle = vector<int>();

		var find_min_huan = [&](var dfs, int now, int fa)->void {
			vis[now] = 1;
			dfn[now] = ++timer;
			dep[now] = dep[fa] + 1;

			for (int to : g[now]) {
				if (to == fa)continue;

				if (vis[to]) {
					if (dfn[to] < dfn[now])
						min_siz = min(min_siz, dep[now] - dep[to] + 1);
				}
				else dfs(dfs, to, now);
			}
			};
		var get_min_huan = [&](var dfs, int now, int fa)->bool {
			vis[now] = 1;
			dfn[now] = ++timer;
			par[now] = fa;
			dep[now] = dep[fa] + 1;

			for (int to : g[now]) {
				if (to == fa)continue;

				if (vis[to]) {
					if (dfn[to] < dfn[now]) {
						int cha = dep[now] - dep[to] + 1;
						if (cha == min_siz) {
							int cur = now;
							while (cur != to) {
								min_cycle.pb(cur);
								cur = par[cur];
							}
							min_cycle.pb(to);
							return 1;
						}
					}
				}
				else {
					if (dfs(dfs, to, now))return 1;
				}
			}

			return 0;
			};

		find_min_huan(find_min_huan, 1, 0);
		timer = 0;
		fa(i, 1, n)vis[i] = dfn[i] = 0;
		get_min_huan(get_min_huan, 1, 0);

		if (min_siz <= k) {
			cout << 2 << endl;
			cout << min_siz << endl;
			cout << min_cycle << endl;
		}
		else {
			cout << 1 << endl;
			bool ok = 1;
			k = (k + 1) / 2;
			for (int x : min_cycle) {
				if (ok) {
					cout << x << ' ';
					k--;
					if (k == 0)break;
				}
				ok ^= 1;
			}
			cout << endl;
		}
	}
	return;
}
